torch::Tensor batchnorm2d_forward_cuda(
    torch::Tensor input,
    torch::Tensor running_mean,
    torch::Tensor running_var,
    torch::Tensor weight,
    torch::Tensor bias,
    float eps,
    bool training,
    float momentum);
